kubectl -n elasticsearch exec curl-test -- curl -sk -u elastic:elasticpass \
  -XPUT "https://es-http.elasticsearch.svc:9200/_transform/events-by-service" \
  -H "Content-Type: application/json" \
  -d '{
    "source": {"index": "app-events"},
    "dest": {"index": "app-events-rollup"},
    "pivot": {
      "group_by": {"service": {"terms": {"field": "service.keyword"}}},
      "aggregations": {"event_count": {"value_count": {"field": "service.keyword"}}}
    },
    "sync": {"time": {"field": "@timestamp", "delay": "1s"}}
  }'
